%[text] #  Week 7
%[text] ## Linear Fit
% Define the vectors x and y
x = [1, 2, 3, 4, 5, 6, 7];
y = [2.2, 2.8, 3.6, 4.5, 5.1, 6.1, 6.9];

% Perform linear fit
coeffs = polyfit(x, y, 1);

% Evaluate the polynomial at the given x points
y_fit = polyval(coeffs, x);

figure; %[output:9d440a78]
plot(x, y, 'bd', x, y_fit, 'r-'); %[output:9d440a78]
title('Linear Fit'); %[output:9d440a78]
xlabel('x'); %[output:9d440a78]
ylabel('y'); %[output:9d440a78]
legend('Data', 'Linear Fit'); %[output:9d440a78]
% Display the coefficients: ax+b
disp(coeffs) %[output:4db5f3b7]
%%
%[text] ## Quadratic Fit
% Define the vectors x and y
x = [1, 2, 3, 4, 5];
y = [2.2, 2.8, 3.6, 4.5, 5.1];

% Perform quadratic fit, the last parameter of polyfit is 2
% you get coeffs as a vector of 1*3
coeffs = polyfit(x, y, 2);

% Evaluate the polynomial at the given x points
y_fit = polyval(coeffs, x);

figure; %[output:43ea3442]
plot(x, y, 'ro', x, y_fit, 'b-'); %[output:43ea3442]
title('Quadratic Fit'); %[output:43ea3442]
xlabel('x'); %[output:43ea3442]
ylabel('y'); %[output:43ea3442]
legend('Data', 'Quadratic Fit'); %[output:43ea3442]
% Display the coefficients: ax^2+bx+c
disp(coeffs) %[output:22531687]
%%
%[text] ## Higher Degree Polynomial Fit
% Define the vectors x and y
x = [1, 2, 3, 4, 5, 9, 18];
y = [2.2, 2.8, 3.6, 4.5, 5.1, 9.7, 10.7];

% Perform quadratic fit, the last parameter of polyfit is 4
% you get coeffs as a vector of 1*5
coeffs = polyfit(x, y, 4);

% Generate a finer x vector for a smoother fit curve
x_fine = linspace(min(x), max(x), 100);
y_fit = polyval(coeffs, x_fine);

figure; %[output:1c549957]
plot(x, y, 'ro', x_fine, y_fit, 'b-'); %[output:1c549957]
title('Polynomial Fit (Degree 4)'); %[output:1c549957]
xlabel('x'); %[output:1c549957]
ylabel('y'); %[output:1c549957]
legend('Data', 'Polynomial Fit'); %[output:1c549957]
% Display the coefficients
disp(coeffs) %[output:42522371]
%%
% Since x has too fewer datapoints, 
% and the 4th order curve is not obvious
figure; %[output:8e7bf46d]
plot(x, y, 'ro', x, polyval(coeffs, x), 'b-'); %[output:8e7bf46d]
title('Polynomial Fit (Degree 4) without smoothing'); %[output:8e7bf46d]
%%
%[text] ## Linear Fit and Error Analysis
% Define the vectors x and y
x = [1, 2, 3, 4, 5];
y = [2.2, 2.8, 3.6, 4.5, 5.1];

% Perform linear fit
coeffs = polyfit(x, y, 1);

% Evaluate the polynomial at the given x points
y_fit = polyval(coeffs, x);

% Calculate R-squared value
SSE = sum((y - y_fit).^2); % or SSE = sum((y - y_fit).*(y - y_fit));
SST = sum((y - mean(y)) .^2); % or SST = sum((y - mean(y)).*(y - mean(y)));
rSquared = 1 - (SSE / SST);
%%
%[text] ## Plot in a fancy way! 
% Calculate errors
AbsoluteError = abs(y - y_fit);

% Create a 2x2 subplot
figure; %[output:3c933bf4]
subplot(2, 2, 1); %[output:3c933bf4]
plot(x, y, 'ro', x, y_fit, 'b-'); %[output:3c933bf4]
title('Linear Fit'); %[output:3c933bf4]
xlabel('x'); %[output:3c933bf4]
ylabel('y'); %[output:3c933bf4]
legend('Data', 'Linear Fit'); %[output:3c933bf4]

subplot(2, 2, 2); %[output:3c933bf4]
% this is just display two coeffs in a sub-plot
text(0.1, 0.5, sprintf('Slope: %.2f\nIntercept: %.2f', coeffs(1), coeffs(2)), 'FontSize', 12); %[output:3c933bf4]
axis off; %[output:3c933bf4]
title('Coefficients'); %[output:3c933bf4]

subplot(2, 2, 3); %[output:3c933bf4]
plot(x, AbsoluteError, 'ko-'); %[output:3c933bf4]
title('Absolute Error'); %[output:3c933bf4]
xlabel('x'); %[output:3c933bf4]
ylabel('Absolute Error'); %[output:3c933bf4]

subplot(2, 2, 4); %[output:3c933bf4]
% this is just display two coeffs in a sub-plot
text(0.1, 0.5, sprintf('R^2: %.4f\n', rSquared), 'FontSize', 12); %[output:3c933bf4]
axis off; %[output:3c933bf4]
title('Error Analysis'); %[output:3c933bf4]
%%
%[text] ## Find where the maximum error is 
AbsoluteError = abs(y - y_fit);
[maxerror, maxloc] = max(AbsoluteError) %[output:406388ae] %[output:24718605]
%[text] Use `gtext` function to put that information on the graph
figure; %[output:190f8403]
plot(x, y, 'ro', x, y_fit, 'b-'); %[output:190f8403]
gtext(['The maximum error is ', num2str(maxerror), ' at index=', num2str(maxloc)]) %[output:190f8403]
%%
%[text] ## Error Analysis of High-order Fit and Predict Value
% Define the vectors x and y
x = [1, 2, 3, 4, 5, 9, 18];
y = [2.2, 2.8, 3.6, 4.5, 5.1, 9.7, 10.7];

% Perform quadratic fit, the last parameter of polyfit is 4
% you get coeffs as a vector of 1*5
coeffs = polyfit(x, y, 4);

% To analyze error, you have to stick to original x
y_fit = polyval(coeffs, x);

figure; %[output:53efc1c2]
plot(x, y, 'ro', x, y_fit, 'b-'); %[output:53efc1c2]
title('Polynomial Fit (Degree 4 without smoothing)'); %[output:53efc1c2]
xlabel('x'); %[output:53efc1c2]
ylabel('y'); %[output:53efc1c2]
legend('Data', 'Polynomial Fit'); %[output:53efc1c2]
SSE = sum((y - y_fit).^2); % or SSE = sum((y - y_fit).*(y - y_fit));
SST = sum((y - mean(y)) .^2); % or SST = sum((y - mean(y)).*(y - mean(y)));
rSquared = 1 - (SSE / SST);
disp(rSquared) %[output:0cc93629]
%[text] Use this new curve to predict a value at x=16
% Method 1: y = ax^4+bx^3+cx^2+dx+e
x0 = 16;
predicted_y = coeffs(1)*(x0)^4+coeffs(2)*(x0)^3+coeffs(3)*(x0)^2+coeffs(4)*(x0)^1+coeffs(5)*(x0)^0;
disp(predicted_y) %[output:71a9ae07]
%Method 2: polyval is not only for a whole vector but for a single value
method2_predicted_y = polyval(coeffs, x0);
disp(method2_predicted_y) %[output:7a7fa80e]
%%
%[text] ## Practice `gtext` again
figure; %[output:4cf61700]
plot(x, y, 'ro', x, y_fit, 'b-'); %[output:4cf61700]
gtext(['The predicted y at x=', num2str(x0), ' is ', num2str(method2_predicted_y)]) %[output:4cf61700]
