%[text] ## Review: HW9 Trace Problem
% Main Program
x=[0 1 4 5 3 2 0 3 5 4 1 0];
a=0;
c=5;
num=0;
%Loops
for i=2:2:length(x)-1 %[output:group:10a7caaa]
    b=7;
    switch x(i)
        case 4
            x(b)=99;
            disp(x) %[output:6d63fd85]
            h=mod(i,2) %[output:2f3dfb42]
        case 1
            summing=0;
            while b<=10
                summing=summing+b;
                b=b+1;
            end
            disp(['Summing is ',num2str(summing)]) %[output:8fd215ba]
            disp(['Result is ',num2str(floor(x(i)/2))]) %[output:728abf74]
        otherwise
            [a,b,c]=Fun3(a,b,c,i);
            disp(['a is ', num2str(a), ' b is ',num2str(b), ' c is ',num2str(c)]) %[output:1413d6a3]
    end
    num=num+1;
end
disp(['num is ',num2str(num)])
disp(['i is ',num2str(i)])

%%%%%%%%%%%%%Function%%%%%%%%%%%%%%
function [c,a,b]=Fun3(c,a,b,i)
    x=[1 2 3 4 5 6 7 8];
    if i==2
        c = x(i/2);
    end
    b=a+b+c;
    a=x(1)+c;
    c=3;
end %[output:group:10a7caaa] %[output:33846d8d] %[output:0476d016]
