%[text] ## Review: HW8 Trace Problem
% Main Program
disp(((15-3+2*4)/5)^2-2^3)
disp(6-10*2/2^2)

num_loops=0;
main1=-5;

for i = 5:3:16
    x = 10-i;
    y = 2*i;
    main1 = main1+confuse1(i,x,y);
    num_loops=num_loops+1;
end

disp(['num loops: ',num2str(num_loops)])
disp(['main1: ',num2str(main1)])

%%%%%%%%%%%%%Function%%%%%%%%%%%%%%
function temp=confuse1(i,y,x)
    if i > 10
        i=i-10;
    end
    switch (i)
        case {2, 3, 6, 8}
            temp=y-x;
            disp(['case1: i = ',num2str(i)])
            disp(['output = ',num2str(temp)])
        case {0, 4, 5, 7}
            temp=x-y;
            disp(['case2: i = ',num2str(i)])
            disp(['output = ',num2str(temp)])
        otherwise
            temp=x+y;
            disp(['otherwise: i = ',num2str(i)])
            disp(['output = ',num2str(temp)])
    end
end %[output:98cc6c0e] %[output:8432fb44] %[output:4bda8c7a] %[output:8224c304] %[output:71cf0464]
