%[text] ## Review: HW7 (problem 3) Trace Problem
% Main Program
A=[2,4,6,8];
B=[1,3,5,7];

string1='Oh my what a beautiful day';
string2='my life is wonderful';

for i=1:6 %[output:group:5e5d3d07]
    switch i
        case 2
            output=funFunction(string1,1,A(3)-1);
        case 1
            output=round((sum(B))/4);
        case 5
            output='I want';
        case 3
            output=min(B);
        case 4
            output=funFunction(string2,1,A(4));
        otherwise
            output='engineering';
    end
    disp(output) %[output:47124f8e]
end

%%%%%%%%%%%%%Function%%%%%%%%%%%%%%
function [done]=funFunction(array,x,y)
    if x < 1
        done=sum(array);
    else
        for i=x:1:y
            if (i == 1)
                done=[];
            elseif i>3
                done=[done,array(i)];
            end
        end
    end
end %[output:group:5e5d3d07]
