%[text] ## Review: HW6 Trace Problem
% Main Program
x=[2, 1, 7, 0, 6, 1, 3, 3, 8];
y=[-1, 2, 0, 4, 2, 7, 2, -1, 4];
temp= [1,4,2,3,0,6,3,8,1,10];
num_loops=0;

for i = 1:2:10 %[output:group:1c7fde49]
    m = temp(i) %[output:595d95a1] %[output:76ea8869] %[output:17128f51] %[output:6bab54bf] %[output:990005f4]
    MyArray(i) = confusion(m, x, y) ; %[output:18620d8b] %[output:488f2693] %[output:718db00d] %[output:7cd05e5e] %[output:1b7c63ae]
    num_loops=num_loops+1;
end

disp (['num loops: ', num2str(num_loops)])
disp (['main1: ',num2str(sum(MyArray))])

%%%%%%%%%%%%%Function%%%%%%%%%%%%%%
function temp=confusion (i,y,x)
    switch (i)
        case {2, 5, 8, 11}
            temp=((12-4^2*3)/2)+i^2;
            disp(['temp = ', num2str(temp)])
            temp=ceil(temp);
        case {0, 3, 6, 10}
            temp=median(x);
            disp(['temp = ', num2str(temp)])
        otherwise
            temp=y(i)/x(i);
            disp(['temp = ', num2str(temp)])
    end
end %[output:group:1c7fde49] %[output:26075085] %[output:12d3be0f]

